return msg;

msg.response = {
    action: "deleteRemoteCatalog",
    status: "success",
    uniqueId: msg.data.uniqueId
};
return msg;

// Expects msg.data.catalogs = array of catalog objects
const catalogs = msg.data.catalogs || [];
const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';

const docs = catalogs.map(c => {
    let randomPart = '';
    for (let i = 0; i < 12; i++) {
        randomPart += chars[Math.floor(Math.random() * chars.length)];
    }
    const id = Date.now().toString(36) + randomPart;
    return { catalog: c, uniqueId: id };
});

if (docs.length === 0) {
    msg.response = {
        action: "uploadCatalogJson",
        status: "error",
        message: "No catalogue entries found in JSON file."
    };
    return [null, msg];
}

msg._uploadedDocs = docs;
msg.operation = "insertMany";
msg.collection = "cr_catalogues";
msg.payload = docs;
return [msg, null];

msg.response = {
    action: "uploadCatalogJson",
    status: "success",
    catalogs: msg._uploadedDocs || []
};
delete msg._uploadedDocs;
return msg;

msg.operation = "find";
msg.collection = "cr_asset_types";
msg.payload = [
    {},
    { projection: { _id: 0 }, sort: { name: 1 } }
];
return msg;

const items = Array.isArray(msg.payload) ? msg.payload : [];
msg.response = { action: "listAssetTypes", status: "success", items };
delete msg.payload;
return msg;

const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
let randomPart = '';
for (let i = 0; i < 12; i++) {
    randomPart += chars[Math.floor(Math.random() * chars.length)];
}
const id = 'at_' + Date.now().toString(36) + randomPart;

const d = msg.data || {};
const doc = {
    uniqueId: id,
    name: (d.name || '').trim(),
    description: d.description || '',
    icon: d.icon || 'dataset',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
};

if (!doc.name) {
    msg.response = { action: "saveAssetType", status: "error", message: "Name is required" };
    delete msg.payload;
    return [null, msg];
}

msg.uniqueId = id;
msg._newDoc = doc;
msg.operation = "insertOne";
msg.collection = "cr_asset_types";
msg.payload = doc;
return [msg, null];

if (msg.response && msg.response.status === "error") {
    return msg;
}
msg.response = {
    action: "saveAssetType",
    status: "success",
    uniqueId: msg.uniqueId,
    item: msg._newDoc
};
delete msg.payload;
delete msg._newDoc;
return msg;

const d = msg.data || {};
if (!d.uniqueId) {
    msg.response = { action: "updateAssetType", status: "error", message: "uniqueId is required" };
    delete msg.payload;
    return [null, msg];
}
const patch = Object.assign({}, d.patch || {}, { updatedAt: new Date().toISOString() });
msg.uniqueId = d.uniqueId;
msg._patch = patch;
msg.operation = "updateOne";
msg.collection = "cr_asset_types";
msg.payload = [{ uniqueId: d.uniqueId }, { $set: patch }];
return [msg, null];

if (msg.response && msg.response.status === "error") {
    return msg;
}
msg.response = {
    action: "updateAssetType",
    status: "success",
    uniqueId: msg.uniqueId,
    patch: msg._patch
};
delete msg.payload;
delete msg._patch;
return msg;

const d = msg.data || {};
if (!d.uniqueId) {
    msg.response = { action: "deleteAssetType", status: "error", message: "uniqueId is required" };
    delete msg.payload;
    return [null, msg];
}
msg.uniqueId = d.uniqueId;
msg.operation = "deleteOne";
msg.collection = "cr_asset_types";
msg.payload = { uniqueId: d.uniqueId };
return [msg, null];

if (msg.response && msg.response.status === "error") {
    return msg;
}
msg.response = { action: "deleteAssetType", status: "success", uniqueId: msg.uniqueId };
delete msg.payload;
return msg;

msg.collection = "dcm_heartbeats";
msg.operation = "updateOne";
msg.payload = [
  { module: "CatalogueRegistry" },
  { $set: { module: "CatalogueRegistry", at: new Date().toISOString() } },
  { upsert: true }
];
return msg;

const data = msg.data || {};
const auth = String(data.auth || 'none').toLowerCase();
const protocol = String(data.protocol || '').toLowerCase();
const endpoint = (data.baseEndpoint || data.queryEndpoint || '').trim();

msg._testStartMs = Date.now();
msg._testMeta = { auth: auth, protocol: protocol };
msg._testAction = 'testRemoteCatalogConnection';

function errorOut(message) {
    const m = RED.util.cloneMessage(msg);
    m.response = { action: 'testRemoteCatalogConnection', status: 'error', message: message, latency: 0, httpCode: 0 };
    delete m.payload;
    return [null, m];
}

if (auth === 'oauth') {
    return errorOut('OAuth2 connection test is not yet supported.');
}

if (auth === 'token-login') {
    const loginUrl = (data.authLoginEndpoint || '').trim();
    if (!loginUrl) return errorOut('Login endpoint URL is required for Token Login auth.');
    if (!data.authUsername || !data.authPassword) return errorOut('Username and password are required for Token Login auth.');
    msg.url = loginUrl;
    msg.method = 'POST';
    msg.headers = { 'Content-Type': 'application/json', 'Accept': 'application/json' };
    msg.payload = { username: data.authUsername, password: data.authPassword };
    return [msg, null];
}

if (!endpoint) return errorOut('No endpoint URL provided.');

msg.url = endpoint;
msg.method = 'GET';
msg.headers = { 'Accept': 'application/json' };

if (auth === 'bearer') {
    const token = (data.authStaticToken || '').trim();
    if (token) msg.headers['Authorization'] = 'Bearer ' + token;
} else if (auth === 'apikey') {
    const header = (data.authApiKeyHeader || 'X-API-Key').trim();
    const key = (data.authApiKey || '').trim();
    if (key) msg.headers[header] = key;
}

delete msg.payload;
return [msg, null];

const latency = Date.now() - (msg._testStartMs || Date.now());
const code = Number(msg.statusCode || 0);
const meta = msg._testMeta || {};

if (msg.response && msg.response.action === 'testRemoteCatalogConnection') {
    msg.response.latency = msg.response.latency || 0;
    delete msg.payload; delete msg.url; delete msg.method; delete msg.headers;
    delete msg._testStartMs; delete msg._testMeta; delete msg._testAction; delete msg.statusCode;
    return msg;
}

let status = 'error';
let message = '';

if (code >= 200 && code < 400) {
    status = 'success';
    const authLabel = meta.auth === 'token-login' ? ' (Token Login authenticated)'
        : meta.auth === 'bearer' ? ' (Bearer Token)'
        : meta.auth === 'apikey' ? ' (API Key)'
        : meta.auth === 'none' ? ''
        : ' (' + meta.auth + ')';
    message = 'Connection successful' + authLabel + ' \u2014 HTTP ' + code;
} else if (code >= 400 && code < 600) {
    status = 'error';
    message = 'Remote returned HTTP ' + code;
} else if (code === 0) {
    status = 'error';
    message = 'Network error: could not reach endpoint';
} else {
    status = 'error';
    message = 'Unexpected response code: ' + code;
}

msg.response = { action: 'testRemoteCatalogConnection', status: status, message: message, latency: latency, httpCode: code };
delete msg.payload; delete msg.url; delete msg.method; delete msg.headers;
delete msg._testStartMs; delete msg._testMeta; delete msg._testAction; delete msg.statusCode;
return msg;

const filter = {};
if (msg.data && msg.data.catalogueId) filter.catalogueId = msg.data.catalogueId;
if (msg.data && msg.data.localTypeId) filter.localTypeId = msg.data.localTypeId;
msg.collection = 'cr_api_mappings';
msg.operation  = 'find';
msg.payload    = [filter];
return msg;

msg.response = {
    action: 'listApiMappings',
    status: 'success',
    mappings: Array.isArray(msg.payload) ? msg.payload : []
};
delete msg.payload;
return msg;

const d = msg.data || {};
if (!d.catalogueId || !d.localTypeId) {
    msg.response = { action: 'saveApiMapping', status: 'error', message: 'catalogueId and localTypeId required' };
    delete msg.payload;
    return [null, msg];
}
const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
let rnd = '';
for (let i = 0; i < 12; i++) rnd += chars[Math.floor(Math.random() * chars.length)];
const now = new Date().toISOString();
const apiRequest = d.apiRequest || { method: 'GET', pathTemplate: '', queryParams: {}, headers: {}, bodyTemplate: null, notes: '' };
if (d.uniqueId) {
    msg.uniqueId = d.uniqueId;
    msg.collection = 'cr_api_mappings';
    msg.operation  = 'updateOne';
    msg.payload = [{ uniqueId: d.uniqueId }, { $set: {
        catalogueId: d.catalogueId,
        localTypeId: d.localTypeId,
        remoteType: d.remoteType || '',
        apiRequest: apiRequest,
        promptId: d.promptId || '',
        promptVersion: d.promptVersion || '',
        generatedBy: d.generatedBy || 'manual',
        status: d.status || 'active',
        updatedAt: now
    } }];
    msg._newDoc = null;
    return [msg, null];
}
const id = 'am_' + Date.now().toString(36) + rnd;
const doc = {
    uniqueId: id,
    catalogueId: d.catalogueId,
    localTypeId: d.localTypeId,
    remoteType: d.remoteType || '',
    apiRequest: apiRequest,
    promptId: d.promptId || '',
    promptVersion: d.promptVersion || '',
    generatedBy: d.generatedBy || 'manual',
    status: d.status || 'active',
    createdAt: now,
    updatedAt: now
};
msg.uniqueId   = id;
msg._newDoc    = doc;
msg.collection = 'cr_api_mappings';
msg.operation  = 'insertOne';
msg.payload    = doc;
return [msg, null];

if (msg.response && msg.response.status === 'error') return msg;
msg.response = {
    action: 'saveApiMapping',
    status: 'success',
    uniqueId: msg.uniqueId,
    item: msg._newDoc || null
};
delete msg.payload;
delete msg._newDoc;
return msg;

const d = msg.data || {};
if (!d.uniqueId) {
    msg.response = { action: 'deleteApiMapping', status: 'error', message: 'uniqueId required' };
    delete msg.payload;
    return [null, msg];
}
msg.uniqueId = d.uniqueId;
msg.collection = 'cr_api_mappings';
msg.operation  = 'deleteOne';
msg.payload    = [{ uniqueId: d.uniqueId }];
return [msg, null];

if (msg.response && msg.response.status === 'error') return msg;
msg.response = { action: 'deleteApiMapping', status: 'success', uniqueId: msg.uniqueId };
delete msg.payload;
return msg;

const d = msg.data || {};
if (!d.catalogueId || !d.localTypeId || !d.promptId) {
    msg.response = { action: 'generateApiMappingWithAi', status: 'error', message: 'catalogueId, localTypeId, promptId required' };
    delete msg.payload;
    return [null, msg];
}
msg._pendingApiMappingGeneration = {
    catalogueId: d.catalogueId,
    localTypeId: d.localTypeId,
    promptId: d.promptId,
    remoteType: d.remoteType || ''
};
msg.collection = 'sr_prompts';
msg.operation  = 'findOne';
msg.payload    = [{ id: d.promptId }];
return [msg, null];

const arr = Array.isArray(msg.payload) ? msg.payload : (msg.payload ? [msg.payload] : []);
msg._prompt = arr[0] || null;
const d = msg._pendingApiMappingGeneration || {};
msg.collection = 'cr_catalogues';
msg.operation  = 'findOne';
msg.payload    = [{ uniqueId: d.catalogueId }];
return msg;

const arr = Array.isArray(msg.payload) ? msg.payload : (msg.payload ? [msg.payload] : []);
msg._catalogue = arr[0] || null;
const d = msg._pendingApiMappingGeneration || {};
msg.collection = 'cr_asset_types';
msg.operation  = 'findOne';
msg.payload    = [{ uniqueId: d.localTypeId }];
return msg;

const arr = Array.isArray(msg.payload) ? msg.payload : (msg.payload ? [msg.payload] : []);
msg._assetType = arr[0] || null;
const p = msg._prompt || {};
const cat = msg._catalogue || {};
const at = msg._assetType || {};
const pending = msg._pendingApiMappingGeneration || {};
const remoteType = pending.remoteType || at.name || '';
const tplText = p.template || p.templateText || p.text || '';
const catName = (cat.catalog && cat.catalog.catalogName) || cat.catalogName || cat.catalog || cat.name || '';
const catEndpoint = (cat.catalog && cat.catalog.apiEndpoint) || cat.apiEndpoint || cat.baseEndpoint || '';
const catAuth = JSON.stringify((cat.catalog && cat.catalog.auth) || cat.auth || {});
const catIface = (cat.catalog && cat.catalog.interfaceType) || cat.interfaceType || '';
const filled = String(tplText)
    .replace(/\{catalogue_name\}/g, catName)
    .replace(/\{catalogue_endpoint\}/g, catEndpoint)
    .replace(/\{catalogue_auth\}/g, catAuth)
    .replace(/\{catalogue_interface_type\}/g, catIface)
    .replace(/\{local_type_name\}/g, at.name || '')
    .replace(/\{local_type_description\}/g, at.description || '')
    .replace(/\{remote_type\}/g, remoteType);
msg._llmRequest = {
    system: 'You are an API mapping assistant. Return ONLY a JSON object with keys: method, pathTemplate, queryParams, headers, bodyTemplate, notes. No markdown fencing.',
    user: filled
};

// Ask the generic LLM caller to force OpenAI's JSON response format.
msg._llmForceJson = true;
return msg;

const raw = (msg._llmRawResponse || '').toString();
let parsed = null;
let parseErr = '';

if (msg._llmError) {
    msg.response = { action: 'generateApiMappingWithAi', status: 'error', message: msg._llmError };
} else {
    // Robust JSON extraction:
    //   1. Trim whitespace.
    //   2. Strip ALL markdown code fences (```json, ```, at start/end/middle).
    //   3. Slice from the first "{" to the last "}" to tolerate leading/trailing prose.
    //   4. JSON.parse.
    let cleaned = raw.trim();
    cleaned = cleaned.replace(/```(?:json)?/gi, '').replace(/```/g, '').trim();
    const firstBrace = cleaned.indexOf('{');
    const lastBrace  = cleaned.lastIndexOf('}');
    if (firstBrace !== -1 && lastBrace > firstBrace) {
        cleaned = cleaned.slice(firstBrace, lastBrace + 1);
    }
    try {
        parsed = JSON.parse(cleaned);
    } catch (e) {
        parseErr = e.message;
        msg.response = {
            action:  'generateApiMappingWithAi',
            status:  'error',
            message: 'LLM returned non-JSON response',
            detail:  parseErr,
            raw:     raw.slice(0, 500)
        };
        node.warn('genApiMap parse failed: ' + parseErr + ' | raw head: ' + raw.slice(0, 200));
    }
}

if (parsed) {
    const apiRequest = {
        method:       parsed.method       || 'GET',
        pathTemplate: parsed.pathTemplate || '',
        queryParams:  parsed.queryParams  || {},
        headers:      parsed.headers      || {},
        bodyTemplate: parsed.bodyTemplate || null,
        notes:        parsed.notes        || ('AI-generated on ' + new Date().toISOString())
    };
    msg.response = {
        action:        'generateApiMappingWithAi',
        status:        'success',
        apiRequest:    apiRequest,
        promptId:      (msg._pendingApiMappingGeneration && msg._pendingApiMappingGeneration.promptId) || '',
        promptVersion: (msg._prompt && msg._prompt.version) || ''
    };
}

delete msg.payload;
delete msg._llmRawResponse;
delete msg._llmError;
delete msg._llmRequest;
delete msg._llmForceJson;
delete msg._prompt;
delete msg._catalogue;
delete msg._assetType;
delete msg._pendingApiMappingGeneration;
return msg;

// FR-CR-03 provider resolution — look up an active provider from sr_providers.
// Priority: prompt.providerId (if set on the selected prompt) → any default provider → first active provider.
const p = msg._prompt || {};
const promptProviderId = p.providerId || '';
msg._apiMapProviderCandidateId = promptProviderId;
msg.collection = 'sr_providers';
msg.operation  = 'find';
msg.payload    = [{ status: 'active' }, { projection: { _id: 0 }, sort: { isDefault: -1, precedence: 1 } }];
return msg;

// FR-CR-03 provider picker + decryptor (libs[] — no require(), no process.env)
const providers = Array.isArray(msg.payload) ? msg.payload : [];
const pickId = msg._apiMapProviderCandidateId || '';
let chosen = null;
if (pickId) chosen = providers.find(p => p.id === pickId) || null;
if (!chosen) chosen = providers.find(p => p.isDefault) || providers[0] || null;

// Resolve apiKey (KMS-encrypted form used by sr_providers)
let apiKey = '';
if (chosen && chosen.apiKey) {
    if (typeof chosen.apiKey === 'object' && chosen.apiKey.ct) {
        const kmsKey = env.get('DCM_KMS_KEY') || global.get('DCM_KMS_KEY') || '';
        if (kmsKey) {
            try {
                const key = Buffer.from(kmsKey, 'hex');
                const iv = Buffer.from(chosen.apiKey.iv, 'hex');
                const tag = Buffer.from(chosen.apiKey.tag, 'hex');
                const decipher = crypto.createDecipheriv('aes-256-gcm', key, iv);
                decipher.setAuthTag(tag);
                apiKey = decipher.update(chosen.apiKey.ct, 'hex', 'utf8') + decipher.final('utf8');
            } catch (e) {
                apiKey = '';
                node.warn('genApiMap: provider decrypt failed: ' + e.message);
            }
        }
    } else if (typeof chosen.apiKey === 'string') {
        apiKey = chosen.apiKey;
    }
}

// Fall back to legacy flow.openai_api_key if no provider key
if (!apiKey) apiKey = flow.get('openai_api_key') || '';

let endpoint = (chosen && chosen.apiEndpoint) || '';
if (!endpoint && chosen) {
    if (chosen.type === 'anthropic') endpoint = 'https://api.anthropic.com/v1/messages';
    else if (chosen.type === 'ollama') endpoint = 'http://localhost:11434/api/chat';
    else endpoint = 'https://api.openai.com/v1/chat/completions';
}
if (!endpoint) endpoint = 'https://api.openai.com/v1/chat/completions';

msg._resolvedProvider = {
    id:          (chosen && chosen.id) || 'legacy',
    name:        (chosen && chosen.name) || 'Legacy OpenAI (flow.context)',
    type:        (chosen && chosen.type) || 'openai',
    apiEndpoint: endpoint,
    apiKey:      apiKey,
    model:       (chosen && chosen.models && chosen.models.length > 0 && chosen.models[0]) || (chosen && chosen.defaultModel) || flow.get('openai_model') || env.get('OPENAI_MODEL') || 'gpt-3.5-turbo',
    timeout:     (chosen && chosen.timeout) || 60
};

delete msg.payload;
delete msg.collection;
delete msg.operation;
delete msg._apiMapProviderCandidateId;
return msg;
